#include <vector>
#include <algorithm>
#include <set>
using namespace std;

class UnionFind {
public:
    vector<int> parent;
    vector<int> rank;

    UnionFind(int size) {
        parent.resize(size);
        rank.resize(size, 0);
        for (int i = 0; i < size; ++i) {
            parent[i] = i;
        }
    }

    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    bool unionSet(int x, int y) {
        int xRoot = find(x);
        int yRoot = find(y);
        if (xRoot == yRoot) {
            return false;
        }
        if (rank[xRoot] < rank[yRoot]) {
            parent[xRoot] = yRoot;
        } else {
            parent[yRoot] = xRoot;
            if (rank[xRoot] == rank[yRoot]) {
                rank[xRoot]++;
            }
        }
        return true;
    }
};

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    vector<vector<long long>> must_edges;
    vector<vector<long long>> optional_edges;

    for (const auto& edge : edges) {
        if (edge[3] == 1) {
            must_edges.push_back({edge[0], edge[1], edge[2]});
        } else {
            optional_edges.push_back({edge[0], edge[1], edge[2]});
        }
    }

    UnionFind uf(n);
    for (const auto& edge : must_edges) {
        uf.unionSet(edge[0], edge[1]);
    }

    set<int> roots;
    for (int i = 0; i < n; ++i) {
        roots.insert(uf.find(i));
    }
    if (roots.size() == 1) {
        long long min_s = must_edges[0][2];
        for (const auto& edge : must_edges) {
            if (edge[2] < min_s) {
                min_s = edge[2];
            }
        }
        return min_s;
    }

    long long left = 1;
    long long right = 2 * 1e5;
    long long answer = -1;

    auto is_possible = [&](long long target) {
        UnionFind uf_temp(n);
        int count = 0;
        for (const auto& edge : must_edges) {
            if (edge[2] >= target) {
                if (uf_temp.unionSet(edge[0], edge[1])) {
                    count++;
                }
            }
        }

        vector<vector<long long>> no_upgrade;
        vector<vector<long long>> need_upgrade;
        for (const auto& edge : optional_edges) {
            if (edge[2] >= target) {
                no_upgrade.push_back(edge);
            } else if (2 * edge[2] >= target) {
                need_upgrade.push_back(edge);
            }
        }

        for (const auto& edge : no_upgrade) {
            if (uf_temp.unionSet(edge[0], edge[1])) {
                count++;
            }
        }

        int upgrades_used = 0;
        for (const auto& edge : need_upgrade) {
            if (upgrades_used >= k) {
                break;
            }
            if (uf_temp.unionSet(edge[0], edge[1])) {
                count++;
                upgrades_used++;
            }
        }

        set<int> temp_roots;
        for (int i = 0; i < n; ++i) {
            temp_roots.insert(uf_temp.find(i));
        }
        return temp_roots.size() == 1 && upgrades_used <= k;
    };

    while (left <= right) {
        long long mid = (left + right) / 2;
        if (is_possible(mid)) {
            answer = mid;
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    return answer;
}
