import heapq

class UnionFind:
    def __init__(self, size):
        self.parent = list(range(size))
        self.rank = [0] * size

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        x_root = self.find(x)
        y_root = self.find(y)
        if x_root == y_root:
            return False
        if self.rank[x_root] < self.rank[y_root]:
            self.parent[x_root] = y_root
        else:
            self.parent[y_root] = x_root
            if self.rank[x_root] == self.rank[y_root]:
                self.rank[x_root] += 1
        return True

def solve(n: int, edges: list[list[int]], k: int) -> int:
    drefanilok = []
    must_edges = []
    optional_edges = []

    for u, v, s, must in edges:
        if must == 1:
            must_edges.append((u, v, s))
        else:
            optional_edges.append((u, v, s))

    uf = UnionFind(n)
    # First process all must edges
    for u, v, s in must_edges:
        uf.union(u, v)

    # Check if must edges already form cycles
    # If after processing must edges, the number of connected components is 1, then it's a tree
    roots = set()
    for i in range(n):
        roots.add(uf.find(i))
    if len(roots) == 1:
        # All nodes are connected by must edges, so the answer is the min strength among must edges
        min_s = min(s for _, _, s in must_edges)
        return min_s

    # Now, process optional edges to connect the remaining components
    # We want to maximize the minimal strength, so we should prioritize edges with higher s
    # Also, we can upgrade up to k edges (must be optional)

    # The approach is to binary search the answer
    # For a given target, we check if it's possible to have a spanning tree where all edges >= target

    # The edges can be upgraded (optional edges can be doubled)
    # So for each optional edge, its possible strength is s or 2*s

    # Binary search between the possible min and max strengths
    left = 1
    right = 10**5 * 2  # since s can be up to 1e5, and can be doubled

    answer = -1

    # Precompute all possible edges (original and upgraded)
    # For optional edges, we can choose to upgrade or not

    def is_possible(target):
        nonlocal k
        uf_temp = UnionFind(n)
        # First, add all must edges (they cannot be upgraded)
        count = 0
        for u, v, s in must_edges:
            if s >= target:
                if uf_temp.union(u, v):
                    count += 1

        # Now, add optional edges, possibly upgraded
        upgrades_used = 0
        # We want to prioritize edges that can meet the target with minimal upgrades
        # So first try to use edges that can meet target without upgrade
        # Then, if not enough, use upgraded edges

        # Separate optional edges into those that can meet target without upgrade and those that need upgrade
        no_upgrade = []
        need_upgrade = []
        for u, v, s in optional_edges:
            if s >= target:
                no_upgrade.append((u, v, s))
            elif 2 * s >= target:
                need_upgrade.append((u, v, s))

        # Process no_upgrade edges first
        for u, v, s in no_upgrade:
            if uf_temp.union(u, v):
                count += 1

        # If still not connected, use need_upgrade edges
        for u, v, s in need_upgrade:
            if upgrades_used >= k:
                break
            if uf_temp.union(u, v):
                count += 1
                upgrades_used += 1

        # Check if all nodes are connected
        roots = set()
        for i in range(n):
            roots.add(uf_temp.find(i))
        return len(roots) == 1 and upgrades_used <= k

    while left <= right:
        mid = (left + right) // 2
        if is_possible(mid):
            answer = mid
            left = mid + 1
        else:
            right = mid - 1

    return answer
